import java.io.File

// Kotlin calling Java
fun main() {
    val file = File("example.txt")
    file.writeText("Hello from Kotlin!")
    val content = file.readText()
    println(content)

    // Java collections
    val list = java.util.ArrayList<String>()
    list.add("Kotlin")
    list.add("Java")
    println(list)
}

// Annotated for Java callers
@JvmOverloads
fun format(name: String, prefix: String = "Hello") = "$prefix, $name!"
